import std/strutils
import atcoder/extra/numeric/float128

proc emit(
    index: int;
    aHigh, aLow, bHigh, bLow, cHigh, cLow: uint64;
) =
  let
    a = fromBits(aHigh, aLow)
    b = fromBits(bHigh, bLow)
    c = fromBits(cHigh, cLow)
    resultBits = toBits(fusedMultiplyAdd(a, b, c))

  echo "FMA\t", index, "\t",
    toHex(aHigh, 16), "\t",
    toHex(aLow, 16), "\t",
    toHex(bHigh, 16), "\t",
    toHex(bLow, 16), "\t",
    toHex(cHigh, 16), "\t",
    toHex(cLow, 16), "\t",
    toHex(resultBits.high, 16), "\t",
    toHex(resultBits.low, 16)

